import test from 'node:test';
import assert from 'node:assert/strict';

import { CircuitBreaker } from '../src/circuit-breaker.mjs';
import { CircuitOpenError, ClientInputError } from '../src/client-errors.mjs';
import { callService } from '../src/service-client.mjs';

test('a local rejection releases one recovery lane without admitting a peer', async () => {
  const breaker = new CircuitBreaker({ threshold: 1, cooldownMs: 10 });
  await assert.rejects(
    callService(async () => { throw new Error('offline'); }, breaker, () => 0)
  );

  let release;
  const gate = new Promise((resolve) => { release = resolve; });
  const trial = callService(async () => {
    await gate;
    throw new ClientInputError('invalid payload');
  }, breaker, () => 10);

  await assert.rejects(
    callService(async () => 'must not enter', breaker, () => 10),
    CircuitOpenError
  );
  release();
  await assert.rejects(trial, ClientInputError);
  assert.equal(await callService(async () => 'recovered', breaker, () => 10), 'recovered');
  assert.deepEqual(breaker.snapshot(), { state: 'closed', failures: 0, openedAt: null });
});
